import { supabase } from '@/lib/supabase'
import { NextRequest, NextResponse } from 'next/server'
import * as XLSX from 'xlsx'

// 물류사 → 창고 매핑
const DISTRIBUTOR_TO_WAREHOUSE: Record<string, string> = {
  '아임웹': '드림산업',
  '스마트스토어': '드림산업',
  '본사소진': '드림산업',
  '29CM': '투민글로벌',
  'W컨셉': '투민글로벌',
  '무신사': '투민글로벌',
  'CJ온스타일': '투민글로벌'
}

export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const file = formData.get('file') as File
    const warehouseParam = formData.get('warehouse') as string

    if (!file) {
      return NextResponse.json({ error: '파일이 없습니다' }, { status: 400 })
    }

    // 선택된 창고 (dream = 드림산업, tumin = 투민글로벌)
    const targetWarehouse = warehouseParam === 'tumin' ? '투민글로벌' : '드림산업'
    console.log('📦 선택된 창고:', targetWarehouse)

    // 파일명에서 날짜 추출
    // 8자리: "20260421_발주서.xlsx" → "2026-04-21"
    // 6자리: "드림산업익일발주_260511.xlsx" → "2026-05-11"
    const isValidYmd = (y: number, m: number, d: number) =>
      y >= 2020 && y <= 2035 && m >= 1 && m <= 12 && d >= 1 && d <= 31
    const filenameDate = (() => {
      // 8자리 형식 시도
      const m8 = file.name.match(/(\d{8})/)
      if (m8) {
        const s = m8[1]
        const y = parseInt(s.slice(0, 4))
        const mo = parseInt(s.slice(4, 6))
        const da = parseInt(s.slice(6, 8))
        if (isValidYmd(y, mo, da)) {
          return `${s.slice(0, 4)}-${s.slice(4, 6)}-${s.slice(6, 8)}`
        }
      }

      // 6자리 형식 시도 (260511 → 2026-05-11)
      const m6 = file.name.match(/(\d{6})/)
      if (m6) {
        const s = m6[1]
        const y = parseInt('20' + s.slice(0, 2))
        const mo = parseInt(s.slice(2, 4))
        const da = parseInt(s.slice(4, 6))
        if (isValidYmd(y, mo, da)) {
          return `${y}-${s.slice(2, 4)}-${s.slice(4, 6)}`
        }
      }

      return null
    })()
    const fallbackDate = filenameDate || new Date().toISOString().split('T')[0]
    console.log(`📅 기본 날짜 (날짜 컬럼 없는 행에 적용): ${fallbackDate}`)

    // 엑셀 파일 읽기
    const buffer = await file.arrayBuffer()
    const workbook = XLSX.read(buffer, { type: 'buffer' })
    const sheetName = workbook.SheetNames[0]
    const sheet = workbook.Sheets[sheetName]

    // 먼저 배열로 읽어서 헤더 유무 확인
    const rawData = XLSX.utils.sheet_to_json(sheet, { header: 1 }) as any[]

    // 헤더 없는 형식 감지 (드림산업: 마지막 컬럼이 6자리 날짜)
    const firstRowLastCol = rawData[0]?.[rawData[0].length - 1]
    const isNoHeaderFormat = typeof firstRowLastCol === 'number' &&
                            String(firstRowLastCol).length === 6 &&
                            rawData[0]?.length >= 13 // 드림산업은 13개 컬럼

    let data: any[]
    let isNewFormat = false

    if (isNoHeaderFormat) {
      // 헤더 없는 형식 (드림산업 익일발주서)
      console.log('📋 형식: 드림산업 익일발주서 (헤더 없음)')
      data = rawData.map(row => ({
        __index_0: row[0],  // 수령인
        __index_1: row[1],  // 전화번호
        __index_3: row[3],  // 주소
        __index_4: row[4],  // 수량
        __index_5: row[5],  // 바코드
        __index_6: row[6],  // 품명
        __index_7: row[7],  // 배송메모
        __index_8: row[8],  // 송장번호
        __index_9: row[9],  // 주문번호
        __index_12: row[12] // 날짜
      }))
      isNewFormat = true
    } else {
      // 헤더 있는 형식
      data = XLSX.utils.sheet_to_json(sheet) as any[]
      const firstRow = data[0] || {}
      const hasOrderCode = '오더코드' in firstRow || '주문코드' in firstRow
      const hasDateColumn = '날짜' in firstRow
      const hasBarcodeColumn = '__EMPTY_1' in firstRow || '__EMPTY' in firstRow
      const hasDreamKeys =
        '주문번호' in firstRow && '품명' in firstRow && '수취인' in firstRow
      // 드림 형식: (날짜+바코드) OR (주문번호+품명+수취인 헤더)
      isNewFormat = (hasDateColumn && hasBarcodeColumn && !hasOrderCode) ||
                    (hasDreamKeys && !hasOrderCode)
      console.log(`📋 파일 형식: ${isNewFormat ? '드림산업 (헤더 있음)' : '기존 발주조회'}`)
    }

    console.log(`📊 엑셀 데이터 ${data.length}개 행 읽기 완료`)

    // 유효한 바코드 목록 가져오기 (product_name까지 한 번에)
    const { data: productBarcodes } = await supabase
      .from('product_barcodes')
      .select('barcode, product_name')

    const { data: setBarcodes } = await supabase
      .from('set_barcodes')
      .select('set_barcode')

    const validProductBarcodes = new Set(productBarcodes?.map(p => p.barcode))
    const validSetBarcodes = new Set(setBarcodes?.map(s => s.set_barcode))
    const productNameMap = new Map<string, string>()
    productBarcodes?.forEach(p => {
      if (p.barcode) productNameMap.set(p.barcode, p.product_name || '')
    })

    // 바코드 별칭 로드 (포장재 차이 등으로 다른 바코드지만 같은 제품으로 집계)
    const { data: aliasRows } = await supabase
      .from('barcode_aliases')
      .select('alias_barcode, actual_barcode')

    const barcodeAliases = new Map<string, string>()
    aliasRows?.forEach(a => {
      if (a.alias_barcode && a.actual_barcode) {
        barcodeAliases.set(String(a.alias_barcode), String(a.actual_barcode))
      }
    })
    const resolveAlias = (code: string) => barcodeAliases.get(code) || code

    // 세트 구성품 전체 prefetch (루프 내 N+1 쿼리 제거)
    const { data: allCompositions } = await supabase
      .from('set_composition')
      .select('set_barcode, component_barcode, quantity')

    const setCompositionsMap = new Map<string, { product_barcode: string; quantity: number }[]>()
    allCompositions?.forEach(c => {
      if (!c.set_barcode) return
      const list = setCompositionsMap.get(c.set_barcode) || []
      list.push({ product_barcode: c.component_barcode, quantity: c.quantity })
      setCompositionsMap.set(c.set_barcode, list)
    })

    // 데이터 변환 및 검증
    const salesRecords: any[] = []
    const errors: string[] = []
    let skippedCount = 0
    let excludedCount = 0
    const uniqueOrderCodes = new Set<string>()
    const dreamOrderCodes = new Set<string>() // 드림산업 고유 주문번호 추적

    for (let i = 0; i < data.length; i++) {
      const row = data[i]

      let orderCode = ''
      let distributor = ''
      let sku = ''
      let quantity = 0
      let saleDate = ''
      let warehouse = ''

      if (isNewFormat) {
        // 신규 형식 (드림산업 익일발주건 / 발주양식)
        // 헤더 없는 경우: __index_X 사용, 헤더 있는 경우: 컬럼명 사용
        orderCode = String(row['__index_9'] || row['주문번호'] || '')
        sku = String(row['__index_5'] || row['__EMPTY'] || '').trim()
        quantity = parseInt(row['__index_4'] || row['수량'] || '0')
        warehouse = targetWarehouse // 선택된 창고

        // 빈 행(주문번호 없음) 조용히 건너뛰기 - 발주양식 하단 빈 템플릿 행 대응
        if (!orderCode) {
          continue
        }

        // 날짜 추출: 날짜 컬럼이 있으면 그 값, 없거나 비었으면 파일명/오늘 날짜 폴백
        const dateNum = String(row['__index_12'] || row['__EMPTY_1'] || row['날짜'] || '')
        if (dateNum.length === 6) {
          // 6자리: 260102
          const y = parseInt('20' + dateNum.substring(0, 2))
          const m = parseInt(dateNum.substring(2, 4))
          const d = parseInt(dateNum.substring(4, 6))
          if (!isValidYmd(y, m, d)) {
            errors.push(`행 ${i + 2}: 날짜 형식 오류 (${dateNum})`)
            continue
          }
          saleDate = `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
        } else if (dateNum.length === 8) {
          // 8자리: 20260102
          const y = parseInt(dateNum.substring(0, 4))
          const m = parseInt(dateNum.substring(4, 6))
          const d = parseInt(dateNum.substring(6, 8))
          if (!isValidYmd(y, m, d)) {
            errors.push(`행 ${i + 2}: 날짜 형식 오류 (${dateNum})`)
            continue
          }
          saleDate = `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
        } else {
          // 날짜 컬럼 없음/빈값 → 파일명 날짜 또는 오늘 (발주양식 송장입력 등)
          saleDate = fallbackDate
        }

        // 택배건수 계산용 (주문제작 포함)
        if (orderCode) {
          uniqueOrderCodes.add(orderCode)
          // 드림산업 송장건수 추적
          if (warehouse === '드림산업') {
            dreamOrderCodes.add(orderCode)
          }
        }

        // 배송메모에 "증정", "사은품", "협찬" 키워드가 있으면 제외
        const memo = String(row['__index_7'] || row['배송메모'] || '').trim()
        if (memo.includes('증정') || memo.includes('사은품') || memo.includes('협찬')) {
          excludedCount++
          continue
        }

        // 품명에 "협찬" 키워드가 있으면 제외 (SKU 유무와 무관)
        const productNameDream = String(row['__index_6'] || row['품명'] || '')
        if (productNameDream.includes('협찬')) {
          excludedCount++
          continue
        }

        // 바코드가 없으면 품명에서 주문제작 여부 확인
        if (!sku) {
          const productName = String(row['__index_6'] || row['품명'] || '')

          // 증정/사은품/포장재는 제외
          if (productName.includes('증정') || productName.includes('사은품') || productName.includes('포장재')) {
            excludedCount++
            continue
          }

          // 주문제작/필수입력 옵션 주문인 경우 카테고리별로 집계
          // "색상" + "디자인" 둘 다 포함되면 옵션 기반 커스텀 주문
          const hasColorAndDesign = productName.includes('색상') && productName.includes('디자인')
          if (
            productName.includes('주문제작') ||
            productName.includes('필수입력') ||
            hasColorAndDesign
          ) {
            let customCategory = ''

            if (productName.includes('미니멀')) {
              customCategory = 'CUSTOM_MINIMAL'
            } else if (productName.includes('그레인')) {
              customCategory = 'CUSTOM_GRAIN'
            } else if (productName.includes('사이잘')) {
              customCategory = 'CUSTOM_SISAL'
            } else {
              // 기타는 모두 시어서커로 분류
              customCategory = 'CUSTOM_SHEERSUCKER'
            }

            // 주문제작 레코드 추가
            salesRecords.push({
              sale_date: saleDate,
              warehouse,
              product_barcode: customCategory,
              quantity,
              order_id: null,
              is_manual: false
            })
            continue
          }

          // 주문제작도 아니고 바코드도 없으면 오류
          errors.push(`행 ${i + 1}: 바코드 없음 (품명: ${productName || '없음'})`)
          continue
        }
      } else {
        // 기존 형식 (발주조회)
        orderCode = row['오더코드'] || row['주문코드'] || row['order_code'] || ''
        distributor = row['발주 타입'] || row['물류사'] || row['distributor'] || ''
        sku = row['고유코드'] || row['SKU'] || row['sku'] || ''
        quantity = parseInt(row['수량'] || row['quantity'] || '0')

        // 협찬, 본사소진 제외
        if (distributor === '협찬' || distributor === '본사소진') {
          excludedCount++
          continue
        }

        // 배송메모에 "증정", "사은품" 키워드가 있으면 제외
        const memo = String(row['배송메모'] || row['memo'] || '').trim()
        if (memo.includes('증정') || memo.includes('사은품')) {
          excludedCount++
          continue
        }

        // 상품명에 "증정/사은품/행사/포장재" 키워드가 있으면 제외 (SKU 유무와 무관)
        const productNameEarly = String(row['판매상품명'] || row['상품명'] || row['품명'] || '')
        if (
          productNameEarly.includes('증정') ||
          productNameEarly.includes('사은품') ||
          productNameEarly.includes('행사') ||
          productNameEarly.includes('포장재')
        ) {
          excludedCount++
          continue
        }

        if (!orderCode) {
          errors.push(`행 ${i + 2}: 주문코드 누락`)
          continue
        }

        // 날짜 추출 (O20260102-00338 → 2026-01-02)
        const dateMatch = orderCode.match(/O(\d{4})(\d{2})(\d{2})/)
        if (!dateMatch) {
          errors.push(`행 ${i + 2}: 주문코드 형식 오류 (${orderCode})`)
          continue
        }

        saleDate = `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}`

        // 창고는 선택된 창고 사용 (발주 타입과 무관)
        warehouse = targetWarehouse

        // 택배건수 계산용 (주문제작 포함)
        if (orderCode) {
          uniqueOrderCodes.add(orderCode)
        }

        // SKU 없으면 품명에서 주문제작 여부 확인
        if (!sku) {
          const productName = String(row['판매상품명'] || row['상품명'] || row['품명'] || '')

          // 증정/사은품/행사/포장재는 제외
          if (
            productName.includes('증정') ||
            productName.includes('사은품') ||
            productName.includes('행사') ||
            productName.includes('포장재')
          ) {
            excludedCount++
            continue
          }

          // 주문제작인 경우 카테고리별로 집계
          if (productName.includes('주문제작')) {
            let customCategory = ''

            if (productName.includes('미니멀')) {
              customCategory = 'CUSTOM_MINIMAL'
            } else if (productName.includes('그레인')) {
              customCategory = 'CUSTOM_GRAIN'
            } else if (productName.includes('사이잘')) {
              customCategory = 'CUSTOM_SISAL'
            } else {
              // 기타는 모두 시어서커로 분류
              customCategory = 'CUSTOM_SHEERSUCKER'
            }

            // 주문제작 레코드 추가
            salesRecords.push({
              sale_date: saleDate,
              warehouse,
              product_barcode: customCategory,
              quantity,
              order_id: null,
              is_manual: false
            })
            continue
          }

          // 주문제작도 아니고 SKU도 없으면 오류
          errors.push(`행 ${i + 1}: SKU 없음 (품명: ${productName || '없음'})`)
          continue
        }
      }

      // 별칭 치환 (포장재 차이 등)
      sku = resolveAlias(sku)

      // 바코드 검증 (단품 또는 세트)
      const isProduct = validProductBarcodes.has(sku)
      const isSet = validSetBarcodes.has(sku)

      if (!isProduct && !isSet) {
        // 마지막으로 품명 확인
        const productName = String(isNewFormat ? row['품명'] : (row['판매상품명'] || row['상품명'] || row['품명'])) || ''

        if (productName.includes('주문제작')) {
          let customCategory = ''

          if (productName.includes('미니멀')) {
            customCategory = 'CUSTOM_MINIMAL'
          } else if (productName.includes('그레인')) {
            customCategory = 'CUSTOM_GRAIN'
          } else if (productName.includes('사이잘')) {
            customCategory = 'CUSTOM_SISAL'
          } else {
            customCategory = 'CUSTOM_ETC'
          }

          salesRecords.push({
            sale_date: saleDate,
            warehouse,
            product_barcode: customCategory,
            quantity,
            order_id: null,
            is_manual: false
          })
          continue
        }

        // 주문제작도 아니고 바코드 매칭도 안되면 오류
        errors.push(`행 ${i + 1}: 매칭되지 않은 바코드 "${sku}" (품명: ${productName || '없음'})`)
        continue
      }

      if (isSet) {
        // 세트인 경우: 구성품으로 분해 (prefetch된 맵 사용)
        const compositions = setCompositionsMap.get(sku) || []
        for (const comp of compositions) {
          salesRecords.push({
            sale_date: saleDate,
            warehouse,
            product_barcode: comp.product_barcode,
            quantity: comp.quantity * quantity,
            order_id: null,
            is_manual: false
          })
        }
      } else {
        // 단품인 경우: 그대로 추가
        salesRecords.push({
          sale_date: saleDate,
          warehouse,
          product_barcode: sku,
          quantity,
          order_id: null,
          is_manual: false
        })
      }
    }

    console.log(`✅ 변환 완료: ${salesRecords.length}개`)
    console.log(`⚠️  건너뜀: ${skippedCount}개 (바코드 미등록)`)

    // 매칭되지 않은 바코드가 있으면 업로드 중단
    if (errors.length > 0) {
      console.log(`❌ 오류 ${errors.length}건 - 상위 20개:`)
      errors.slice(0, 20).forEach(e => console.log('  -', e))
      return NextResponse.json({
        success: false,
        message: `업로드 실패: ${errors.length}개의 매칭되지 않은 바코드 발견`,
        errors: errors
      }, { status: 400 })
    }

    // 원본 주문 정보를 sales_orders에 저장 (택배건수 추적용)
    // 송장번호가 있는 행만 추출 + 중복 제거 (합배송 처리)
    const trackingNumberMap = new Map<string, { orderDate: string | null; warehouse: string; orderCode: string }>()

    data.forEach(row => {
      let trackingNo = ''
      let orderDate = null
      let warehouse = '드림산업'
      let orderCode = ''

      if (isNewFormat) {
        // 신규 형식 (드림산업): 송장번호 추출
        trackingNo = String(row['__index_8'] || row['송장번호'] || '').trim()
        orderCode = String(row['__index_9'] || row['주문번호'] || '').trim()

        if (!trackingNo) return // 송장번호 없으면 스킵

        // 날짜 추출
        const dateNum = String(row['__index_12'] || row['__EMPTY_1'] || row['날짜'] || '')
        if (dateNum.length === 6) {
          // 6자리: 260102
          const year = '20' + dateNum.substring(0, 2)
          const month = dateNum.substring(2, 4)
          const day = dateNum.substring(4, 6)
          orderDate = `${year}-${month}-${day}`
        } else if (dateNum.length === 8) {
          // 8자리: 20260102
          const year = dateNum.substring(0, 4)
          const month = dateNum.substring(4, 6)
          const day = dateNum.substring(6, 8)
          orderDate = `${year}-${month}-${day}`
        } else {
          orderDate = fallbackDate
        }
        warehouse = targetWarehouse
      } else {
        // 기존 형식 (투민글로벌): 주문코드에서 날짜 추출
        orderCode = String(row['오더코드'] || row['주문코드'] || '').trim()
        if (!orderCode) return // 주문코드 없으면 스킵

        const match = orderCode.match(/O(\d{4})(\d{2})(\d{2})/)
        orderDate = match ? `${match[1]}-${match[2]}-${match[3]}` : null
        warehouse = targetWarehouse
        trackingNo = orderCode // 기존 형식은 주문코드를 송장번호로 사용
      }

      // 송장번호로 중복 제거 (합배송은 택배건수 1건)
      if (trackingNo && orderDate && !trackingNumberMap.has(trackingNo)) {
        trackingNumberMap.set(trackingNo, { orderDate, warehouse, orderCode })
      }
    })

    const orderRecords = Array.from(trackingNumberMap.entries()).map(([trackingNo, info]) => ({
      order_date: info.orderDate,
      warehouse: info.warehouse,
      barcode: trackingNo, // 송장번호를 바코드로 저장
      order_number: info.orderCode || trackingNo,
      is_set: false,
      quantity: 1,
      order_type: '일반',
      created_by: 'system',
      created_at: new Date().toISOString()
    }))

    // sales_orders에 주문 저장 (배치 최적화)
    if (orderRecords.length > 0) {
      // 기존 주문 바코드 일괄 조회
      const barcodes = orderRecords.map(o => o.barcode)
      const { data: existingOrders } = await supabase
        .from('sales_orders')
        .select('barcode')
        .in('barcode', barcodes)

      const existingBarcodes = new Set(existingOrders?.map(o => o.barcode) || [])

      // 신규 주문만 필터링
      const newOrders = orderRecords.filter(o =>
        o.order_date && !existingBarcodes.has(o.barcode)
      )

      // 배치 삽입 (500개씩)
      if (newOrders.length > 0) {
        const batchSize = 500
        for (let i = 0; i < newOrders.length; i += batchSize) {
          const batch = newOrders.slice(i, i + batchSize)
          await supabase.from('sales_orders').insert(batch)
        }
        console.log(`📦 주문 저장: ${newOrders.length}개`)
      }
    }

    // 날짜/창고/바코드별로 집계
    const aggregated = salesRecords.reduce((acc, rec) => {
      const key = `${rec.sale_date}|${rec.warehouse}|${rec.product_barcode}`
      if (!acc[key]) {
        acc[key] = { ...rec, quantity: 0 }
      }
      acc[key].quantity += rec.quantity
      return acc
    }, {} as Record<string, any>)

    const aggregatedRecords = Object.values(aggregated) as any[]

    // 창고별 통계
    const dreamRecords = salesRecords.filter(r => r.warehouse === '드림산업')
    const dreamInvoiceCount = dreamOrderCodes.size // 드림산업 송장건수
    const dreamProductQuantity = dreamRecords.reduce((sum, r) => sum + r.quantity, 0) // 드림산업 제품수량

    const tuminCount = aggregatedRecords.filter(r => r.warehouse === '투민글로벌').length

    // UPSERT 최적화: 배치 처리
    // 1. 업로드할 날짜 범위 추출
    const dates = [...new Set(aggregatedRecords.map(r => r.sale_date))].sort()
    const minDate = dates[0]
    const maxDate = dates[dates.length - 1]

    console.log(`📅 업로드 날짜 범위: ${minDate} ~ ${maxDate}`)

    // 2. 해당 날짜/창고의 기존 데이터 일괄 조회
    const { data: existingData } = await supabase
      .from('daily_sales')
      .select('*')
      .eq('warehouse', targetWarehouse)
      .gte('sale_date', minDate)
      .lte('sale_date', maxDate)

    console.log(`📦 기존 데이터: ${existingData?.length || 0}개`)

    // 3. 기존 데이터를 맵으로 변환
    const existingMap = new Map<string, any>()
    existingData?.forEach(item => {
      const key = `${item.sale_date}|${item.warehouse}|${item.product_barcode}`
      existingMap.set(key, item)
    })

    // 4. 신규 데이터와 병합
    const toUpdate: any[] = []
    const toInsert: any[] = []
    let insertedCount = 0
    let updatedCount = 0

    // 업로드된 바코드 추적
    const uploadedKeys = new Set<string>()

    aggregatedRecords.forEach(record => {
      const key = `${record.sale_date}|${record.warehouse}|${record.product_barcode}`
      uploadedKeys.add(key)
      const existing = existingMap.get(key)

      if (existing) {
        // 기존 데이터가 있으면 수량 합산
        toUpdate.push({
          id: existing.id,
          quantity: parseFloat(existing.quantity) + record.quantity
        })
        updatedCount++
      } else {
        // 신규 데이터
        toInsert.push(record)
        insertedCount++
      }
    })

    // 5. 업데이트 (배치)
    if (toUpdate.length > 0) {
      for (const item of toUpdate) {
        await supabase
          .from('daily_sales')
          .update({
            quantity: item.quantity,
            updated_at: new Date().toISOString()
          })
          .eq('id', item.id)
      }
    }

    // 6. 신규 삽입 (배치)
    let insertFailedMessage: string | null = null
    if (toInsert.length > 0) {
      const batchSize = 500
      for (let i = 0; i < toInsert.length; i += batchSize) {
        const batch = toInsert.slice(i, i + batchSize)
        const { error: insertError } = await supabase.from('daily_sales').insert(batch)
        if (insertError) {
          console.error('❌ daily_sales insert 실패:', insertError)
          insertFailedMessage = insertError.message || 'daily_sales 저장 실패'
          insertedCount = 0
          break
        }
      }
    }

    if (insertFailedMessage) {
      return NextResponse.json({
        success: false,
        message: `판매 데이터 저장 실패: ${insertFailedMessage}`,
        errors: [insertFailedMessage]
      }, { status: 500 })
    }

    console.log(`✅ 처리 완료: 신규 ${insertedCount}개, 업데이트 ${updatedCount}개`)

    // 7. 출고관리 테이블에도 자동 저장
    let shipmentCount = 0
    try {
      if (targetWarehouse === '드림산업' && isNewFormat) {
        // 제조사 출고 데이터 (manufacturer_shipment_data)
        const manufacturerShipments = data.map((row) => ({
          order_number: String(row['__index_9'] || row['주문번호'] || ''),
          recipient_name: String(row['__index_0'] || ''),
          phone: String(row['__index_1'] || ''),
          address: String(row['__index_3'] || ''),
          product_name: String(row['__index_6'] || row['품명'] || ''),
          quantity: parseInt(row['__index_4'] || row['수량'] || '0'),
          tracking_no: String(row['__index_8'] || ''),
          request_note: String(row['__index_7'] || ''),
          upload_date: (() => {
            const dateNum = String(row['__index_12'] || row['날짜'] || '')
            if (dateNum.length === 6) {
              const y = parseInt('20' + dateNum.substring(0, 2))
              const m = parseInt(dateNum.substring(2, 4))
              const d = parseInt(dateNum.substring(4, 6))
              if (isValidYmd(y, m, d)) {
                return `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
              }
            } else if (dateNum.length === 8) {
              const y = parseInt(dateNum.substring(0, 4))
              const m = parseInt(dateNum.substring(4, 6))
              const d = parseInt(dateNum.substring(6, 8))
              if (isValidYmd(y, m, d)) {
                return `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
              }
            }
            return fallbackDate
          })()
        })).filter(s => s.order_number && s.upload_date)

        if (manufacturerShipments.length > 0) {
          const { error: shipmentError } = await supabase
            .from('manufacturer_shipment_data')
            .insert(manufacturerShipments)

          if (shipmentError) {
            console.error('제조사 출고 데이터 저장 실패:', shipmentError)
          } else {
            shipmentCount = manufacturerShipments.length
            console.log(`📦 제조사 출고 데이터 저장: ${shipmentCount}건`)
          }
        }
      } else if (targetWarehouse === '투민글로벌') {
        // 3PL 출고 데이터 (daily_shipment_data)
        // 일별현황과 동일하게 세트 분해 + 바코드 검증 (prefetch된 맵 사용)
        const shipments: any[] = []

        for (const row of data) {
          const orderCode = row['오더코드'] || row['주문코드'] || ''
          let sku = String(row['고유코드'] || row['SKU'] || '').trim()
          const quantity = parseInt(row['수량'] || '0')
          let uploadDate = ''

          // 날짜 추출 (O20260415-00138 → 2026-04-15)
          const dateMatch = orderCode.match(/O(\d{4})(\d{2})(\d{2})/)
          if (dateMatch) {
            uploadDate = `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}`
          }

          if (!orderCode || !uploadDate || !sku) continue

          // 별칭 치환 (포장재 차이 등)
          sku = resolveAlias(sku)

          // 바코드 검증
          const isValidProduct = validProductBarcodes.has(sku)
          const isValidSet = validSetBarcodes.has(sku)

          if (!isValidProduct && !isValidSet) continue

          // 기본 주문 정보
          const baseShipment = {
            order_code: String(orderCode),
            order_memo: String(row['상품별 메모1'] || ''),
            distributor: String(row['발주 타입'] || row['물류사'] || ''),
            courier: String(row['택배사'] || ''),
            tracking_no: String(row['송장번호'] || ''),
            upload_date: uploadDate
          }

          if (isValidSet) {
            // 세트인 경우: 구성품으로 분해 (prefetch된 맵 사용)
            const compositions = setCompositionsMap.get(sku) || []
            for (const comp of compositions) {
              shipments.push({
                ...baseShipment,
                sku: comp.product_barcode,
                product_name: productNameMap.get(comp.product_barcode) || comp.product_barcode,
                quantity: comp.quantity * quantity
              })
            }
          } else {
            // 단품인 경우: 그대로 추가
            shipments.push({
              ...baseShipment,
              sku: sku,
              product_name: String(row['판매상품명'] || '') || productNameMap.get(sku) || '',
              quantity: quantity
            })
          }
        }

        if (shipments.length > 0) {
          // 배치로 insert (1000건씩)
          const batchSize = 1000
          let insertError: any = null
          for (let i = 0; i < shipments.length; i += batchSize) {
            const batch = shipments.slice(i, i + batchSize)
            const { error: e } = await supabase
              .from('daily_shipment_data')
              .insert(batch)
            if (e) { insertError = e; break }
          }

          if (insertError) {
            console.error('3PL 출고 데이터 저장 실패:', insertError)
          } else {
            shipmentCount = shipments.length
            console.log(`📦 3PL 출고 데이터 저장: ${shipmentCount}건 (세트 분해 포함)`)
          }
        }
      }
    } catch (shipmentError) {
      console.error('출고 데이터 저장 중 오류:', shipmentError)
      // 출고 데이터 저장 실패해도 판매 데이터는 성공했으므로 계속 진행
    }

    return NextResponse.json({
      success: true,
      message: `업로드 완료: ${insertedCount}개 신규, ${updatedCount}개 업데이트${shipmentCount > 0 ? ` | 출고관리 ${shipmentCount}건 자동 등록` : ''}`,
      stats: {
        total: data.length,
        orderCount: uniqueOrderCodes.size,
        converted: salesRecords.length,
        excluded: excludedCount,
        skipped: skippedCount,
        inserted: insertedCount,
        updated: updatedCount,
        errors: errors.length,
        dreamInvoiceCount,
        dreamProductQuantity,
        tuminCount,
        shipmentCount
      },
      errors: errors.slice(0, 10) // 최대 10개 에러만 반환
    })

  } catch (error) {
    console.error('Upload error:', error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : 'Unknown error' },
      { status: 500 }
    )
  }
}

