import { supabase } from '@/lib/supabase'
import ClientPage from './ClientPage'

export const dynamic = 'force-dynamic'
export const revalidate = 0

// 주차 계산 (목~수 기준)
function getWeekNumber(dateStr: string): number {
  const date = new Date(dateStr)
  const thursday = new Date(date)
  thursday.setDate(date.getDate() + (3 - date.getDay()))
  const firstThursday = new Date(thursday.getFullYear(), 0, 1)
  firstThursday.setDate(firstThursday.getDate() + (3 - firstThursday.getDay()))
  const weekNum = Math.floor((thursday.getTime() - firstThursday.getTime()) / (7 * 24 * 60 * 60 * 1000)) + 1
  return weekNum
}

export default async function ProductGroupsPage() {
  console.log('🔍 제품군별 분석 페이지 데이터 로딩 시작')

  // 제품군별 바코드 패턴 정의 (daily_sales에서 직접 조회)
  const productGroups: Record<string, string[]> = {
    '미니멀러그': ['LE10000%', 'R008535%'],
    '그레인러그': ['LE10400%'],
    '시어서커': ['LE10300%'],
    '사이잘러그': ['LF%'],
    '방석/쿠션': ['LE101%', 'LE201%'],  // 방석, 펫쿠션 포함
    '블랭킷': ['LEC%'],
  }

  // 1. daily_sales에서 2026년 전체 데이터 조회 (바코드 패턴별)
  const salesData: any[] = []

  for (const [groupName, patterns] of Object.entries(productGroups)) {
    for (const pattern of patterns) {
      const { data } = await supabase
        .from('daily_sales')
        .select('*')
        .ilike('product_barcode', pattern)
        .gte('sale_date', '2026-01-01')
        .lte('sale_date', '2026-12-31')

      if (data) {
        // 각 레코드에 제품군 정보 추가
        data.forEach(record => {
          salesData.push({ ...record, group: groupName })
        })
      }
    }
    console.log(`  ${groupName}: 조회 완료`)
  }

  console.log(`  총 조회된 판매 레코드: ${salesData.length}개`)

  // 2. 제품군별 월별/주간별 집계
  const monthlyData: Record<string, Record<number, number>> = {}
  const weeklyData: Record<string, Record<number, number>> = {}
  const totalByGroup: Record<string, number> = {}

  Object.keys(productGroups).forEach(group => {
    monthlyData[group] = {}
    weeklyData[group] = {}
    totalByGroup[group] = 0
  })

  salesData.forEach(record => {
    const group = record.group
    const saleDate = record.sale_date
    const quantity = parseFloat(record.quantity) || 0
    const month = parseInt(saleDate.split('-')[1])
    const week = getWeekNumber(saleDate)

    monthlyData[group][month] = (monthlyData[group][month] || 0) + quantity
    weeklyData[group][week] = (weeklyData[group][week] || 0) + quantity
    totalByGroup[group] = (totalByGroup[group] || 0) + quantity
  })

  console.log('✅ 데이터 집계 완료')
  console.log('제품군별 총계:', totalByGroup)

  return (
    <main className="min-h-screen" style={{ background: '#F6F6F2' }}>
      <div className="max-w-full mx-auto px-8 py-10">
        {/* 페이지 헤더 */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight mb-2" style={{ color: '#212121' }}>
            📊 제품군별 판매 분석
          </h1>
          <p className="text-sm" style={{ color: '#999999' }}>
            미니멀러그, 그레인러그, 시어서커, 사이잘러그 판매량 추이
          </p>
        </div>

        {/* 클라이언트 페이지 */}
        <ClientPage
          monthlyData={monthlyData}
          weeklyData={weeklyData}
          totalByGroup={totalByGroup}
        />
      </div>
    </main>
  )
}

